import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Validate input length before copying
        if (input.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
            return;
        }

        char[] buffer = new char[10];

        // Copy user input into buffer
        for (int i = 0; i < input.length(); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Input copied into buffer: " + new String(buffer));
    }
}

